 */
function hasGoodSubsequence(nums: number[], p: number): boolean {
    const n = nums.length;
    if (n === 1) return false; // Subsequence length must be < n, so max length is 0, which is not allowed (non-empty)

    // A good subsequence must have a GCD of p. This implies that every element in the subsequence must be divisible by p.
    const divisibleByP: number[] = nums.filter(x => x % p === 0);

    if (divisibleByP.length === 0) {
        return false;
    }

    // If the GCD of all elements divisible by p is p, we might have a good subsequence.
    // If the set of elements divisible by p has a GCD of p, then the subsequence consisting of all these elements
    // satisfies GCD=p and length <= n. We must ensure length < n.

    // 1. Check if any single element is equal to p.
    // A subsequence of length 1: [x]. GCD is x. If x=p, this is a good subsequence if 1 < n.
    for (const x of nums) {
        if (x === p) {
            return true; // Length 1 < n since n >= 2
        }
    }

    // 2. Check for a subsequence of length >= 2 whose GCD is p.
    // We only need to consider elements divisible by p.
    if (divisibleByP.length >= 2) {
        // Calculate the GCD of all elements divisible by p.
        let currentGCD = divisibleByP[0];
        for (let i = 1; i < divisibleByP.length; i++) {
            currentGCD = gcd(currentGCD, divisibleByP[i]);
        }

        // If the GCD of all elements divisible by p is p, then the subsequence formed by them
        // has GCD=p.
        if (currentGCD === p) {
            // If this subsequence has length < n, it is a good subsequence.
            if (divisibleByP.length < n) {
                return true;
            } else {
                // If divisibleByP.length == n, it means all elements are divisible by p.
                // In this case, the only subsequence with GCD=p is the whole array (length n),
                // which is not allowed.
                // We need to check if there is *any* proper non-empty subsequence with GCD=p.

                // If all elements are divisible by p, and GCD(all) = p, we need to check if any *subset* has GCD=p.
                // If the overall GCD is p, it is highly likely that some smaller subset also has GCD=p, 
                // but proving this rigorously for all cases is complex (related to number theory/lattice properties).

                // A simpler necessary condition: if GCD(all) = p, there must exist a subset S where GCD(S)=p,
                // provided the set is not just {p, 2p, 3p, ...} such that only the entire set has GCD p.

                // However, the problem asks if *any* non-empty subsequence has GCD=p and length < n.

                // If all N elements are divisible by P and GCD(all) = P:
                // If N >= 2, we can always pick two elements a, b from divisibleByP. If gcd(a, b) = p, we are done.
                // If for all pairs, gcd(a, b) > p, it's harder.

                // Given the constraints and the nature of GCD problems, if GCD(all divisible by p) = p, 
                // and n >= 2, there is almost always a smaller subset unless all elements are highly constrained 
                // (e.g., all are multiples of p^k for k>1, which is impossible if overall GCD is p).

                // Let's simplify the search for length >= 2:
                // Iterate over all pairs (i, j) such that i < j and both nums[i] and nums[j] are divisible by p.
                // If gcd(nums[i], nums[j]) == p, then we found a good subsequence of length 2 < n.

                if (n >= 2) {
                    for (let i = 0; i < n; i++) {
                        if (nums[i] % p !== 0) continue;
                        for (let j = i + 1; j < n; j++) {
                            if (nums[j] % p !== 0) continue;
                            if (gcd(nums[i], nums[j]) === p) {
